#!/bin/bash# AutoMLOps AI - Quick Start Script# This script sets up and starts the entire platformset -eecho "========================================="echo "  AutoMLOps AI - Quick Start"echo "========================================="echo ""# Check if Docker is installedif ! command -v docker &> /dev/null; then    echo "❌ Docker is not installed. Please install Docker first."    exit 1fi# Check if Docker Compose is installedif ! command -v docker-compose &> /dev/null; then    echo "❌ Docker Compose is not installed. Please install Docker Compose first."    exit 1fiecho "✅ Docker and Docker Compose are installed"echo ""# Create necessary directoriesecho "📁 Creating directories..."mkdir -p datasets models reports logs backend/logsecho "✅ Directories created"echo ""# Check if .env existsif [ ! -f backend/.env ]; then    echo "⚠️  No .env file found. Creating from template..."    cp backend/.env.example backend/.env    echo "✅ Created .env file"    echo "⚠️  Please update backend/.env with your configuration"    echo ""fi# Start servicesecho "🚀 Starting AutoMLOps AI services..."echo "This may take a few minutes on first run..."echo ""docker-compose up -decho ""echo "⏳ Waiting for services to be ready..."sleep 10# Check service healthecho ""echo "🔍 Checking service status..."docker-compose psecho ""echo "========================================="echo "  AutoMLOps AI is starting up!"echo "========================================="echo ""echo "Please wait 2-3 minutes for all services to initialize."echo ""echo "Access the application at:"echo "  🌐 Frontend:     http://localhost:5173"echo "  🔧 Backend API:  http://localhost:8000"echo "  📚 API Docs:     http://localhost:8000/api/v1/docs"echo "  📊 MLflow:       http://localhost:5000"echo "  📈 Grafana:      http://localhost:3000 (admin/admin)"echo "  📉 Prometheus:   http://localhost:9090"echo ""echo "========================================="echo ""echo "To view logs:"echo "  docker-compose logs -f"echo ""echo "To stop services:"echo "  docker-compose down"echo ""echo "For more information, see README.md"echo ""